-- Migration 151: move 'Certification Exam at Pearson Vue' from
-- short_description into the per-course `course_<sku>_certification`
-- cms_block for every CompTIA course that carries it.
--
-- Generated by scripts/local-dev/generate-comptia-cert-migration-from-prod.php
-- (scrapes tertiarycourses.com.sg as the source of truth).
--
-- cms_block.identifier has NO unique index on this schema, so we
-- use a 2-step upsert (UPDATE first, INSERT if not exists) instead
-- of INSERT...ON DUPLICATE KEY UPDATE — the latter would silently
-- create duplicates that confuse the cms_block loader.
--
-- short_description UPDATEs are MD5-guarded against the prod value
-- captured at generation time. Safe to re-run; on a DB whose
-- short_description has diverged from prod the UPDATE no-ops.

-- TGS-2024048318 (entity_id=25, 1 store row(s))
UPDATE cms_block SET content = '<ul>\r\n<li>\r\n<p><strong>Certificate of Completion from Tertiary Infotech</strong> - Upon meeting at least 75% attendance and passing the assessment(s), participants will receive a Certificate of Completion from Tertiary Infotech.</p>\r\n</li>\r\n<li>\r\n<p><strong>OpenCerts from SkillsFuture Singapore</strong> - After passing the assessment(s) and achieving at least 75% attendance, participants will receive a OpenCert (aka Statement of Achievement) from SkillsFuture Singapore, certifying that they have&nbsp;achieved the Competency Standard(s) in the above Skills Framework.</p>\r\n</li>\r\n<li><strong>External Certification</strong> -&nbsp;<span>The participant will be able to attempt the CompTIA Server+ SK0-005 certification exam after attending this course. Upon passing the exam, you will receive the CompTIA Server+ certification. The CompTIA Server+ certification validates the essential knowledge and skills needed to confidently design, configure, manage, and troubleshoot wired and wireless networks. It covers a wide range of networking concepts including networking technologies, installation and configuration, media and topologies, security, and troubleshooting.</span></li>\r\n</ul>\n<p><strong>Certification Exam at Pearson Vue</strong></p><p>Once you are prepared for the exam, you can register for the certification&nbsp;<span style=\"text-decoration: underline;\"><a href=\"https://home.pearsonvue.com/Clients/CompTIA.aspx\" title=\"CompTia Certification\" target=\"_blank\">here</a></span>. We are Authorised Pearson Vue Testing Center. You can take the certification exam at our test center.</p>', update_time = NOW() WHERE identifier = 'course_TGS-2024048318_certification';
INSERT INTO cms_block (title, identifier, content, is_active, creation_time, update_time) SELECT 'Certification — TGS-2024048318', 'course_TGS-2024048318_certification', '<ul>\r\n<li>\r\n<p><strong>Certificate of Completion from Tertiary Infotech</strong> - Upon meeting at least 75% attendance and passing the assessment(s), participants will receive a Certificate of Completion from Tertiary Infotech.</p>\r\n</li>\r\n<li>\r\n<p><strong>OpenCerts from SkillsFuture Singapore</strong> - After passing the assessment(s) and achieving at least 75% attendance, participants will receive a OpenCert (aka Statement of Achievement) from SkillsFuture Singapore, certifying that they have&nbsp;achieved the Competency Standard(s) in the above Skills Framework.</p>\r\n</li>\r\n<li><strong>External Certification</strong> -&nbsp;<span>The participant will be able to attempt the CompTIA Server+ SK0-005 certification exam after attending this course. Upon passing the exam, you will receive the CompTIA Server+ certification. The CompTIA Server+ certification validates the essential knowledge and skills needed to confidently design, configure, manage, and troubleshoot wired and wireless networks. It covers a wide range of networking concepts including networking technologies, installation and configuration, media and topologies, security, and troubleshooting.</span></li>\r\n</ul>\n<p><strong>Certification Exam at Pearson Vue</strong></p><p>Once you are prepared for the exam, you can register for the certification&nbsp;<span style=\"text-decoration: underline;\"><a href=\"https://home.pearsonvue.com/Clients/CompTIA.aspx\" title=\"CompTia Certification\" target=\"_blank\">here</a></span>. We are Authorised Pearson Vue Testing Center. You can take the certification exam at our test center.</p>', 1, NOW(), NOW() FROM DUAL WHERE NOT EXISTS (SELECT 1 FROM cms_block c WHERE c.identifier = 'course_TGS-2024048318_certification');
INSERT IGNORE INTO cms_block_store (block_id, store_id) SELECT block_id, 0 FROM cms_block WHERE identifier = 'course_TGS-2024048318_certification';

