-- M961 (entity_id=961, 2 store row(s))
UPDATE cms_block SET content = '<ul>\r\n<li>\r\n<p><strong>Certificate of Completion from Tertiary Infotech</strong>&nbsp;- Upon meeting at least 75% attendance and passing the assessment(s), participants will receive a Certificate of Completion from Tertiary Infotech.</p>\r\n</li>\r\n<li><strong>External Certification</strong>&nbsp;-&nbsp;The participant will be able to attempt the CompTIA Linux+ XK0-005 certification exam after attending this course. Upon passing the exam, you will receive the CompTIA Linux+ certification. The CompTIA Linux+ certification validates proficiency in Linux system administration, including installation, maintenance, security, troubleshooting, and scripting. It covers a broad range of topics essential for Linux system administrators, such as command-line operations, file systems and hierarchy, system architecture, system configuration, network settings, security, and troubleshooting.</li>\r\n</ul>\n<p><strong>Certification Exam at Pearson Vue</strong></p><p>Once you are prepared for the exam, you can register for the certification&nbsp;<span style=\"text-decoration: underline;\"><a href=\"https://home.pearsonvue.com/Clients/CompTIA.aspx\" title=\"CompTia Certification\" target=\"_blank\">here</a></span>. We are Authorised Pearson Vue Testing Center. You can take the certification exam at our test center. Note that the course fee does not include the certification exam fee.</p>', update_time = NOW() WHERE identifier = 'course_M961_certification';
INSERT INTO cms_block (title, identifier, content, is_active, creation_time, update_time) SELECT 'Certification — M961', 'course_M961_certification', '<ul>\r\n<li>\r\n<p><strong>Certificate of Completion from Tertiary Infotech</strong>&nbsp;- Upon meeting at least 75% attendance and passing the assessment(s), participants will receive a Certificate of Completion from Tertiary Infotech.</p>\r\n</li>\r\n<li><strong>External Certification</strong>&nbsp;-&nbsp;The participant will be able to attempt the CompTIA Linux+ XK0-005 certification exam after attending this course. Upon passing the exam, you will receive the CompTIA Linux+ certification. The CompTIA Linux+ certification validates proficiency in Linux system administration, including installation, maintenance, security, troubleshooting, and scripting. It covers a broad range of topics essential for Linux system administrators, such as command-line operations, file systems and hierarchy, system architecture, system configuration, network settings, security, and troubleshooting.</li>\r\n</ul>\n<p><strong>Certification Exam at Pearson Vue</strong></p><p>Once you are prepared for the exam, you can register for the certification&nbsp;<span style=\"text-decoration: underline;\"><a href=\"https://home.pearsonvue.com/Clients/CompTIA.aspx\" title=\"CompTia Certification\" target=\"_blank\">here</a></span>. We are Authorised Pearson Vue Testing Center. You can take the certification exam at our test center. Note that the course fee does not include the certification exam fee.</p>', 1, NOW(), NOW() FROM DUAL WHERE NOT EXISTS (SELECT 1 FROM cms_block c WHERE c.identifier = 'course_M961_certification');
