-- TGS-2025053927 (entity_id=985, 1 store row(s))
UPDATE cms_block SET content = '<ul>\r\n<li>\r\n<p><strong>Certificate of Completion from Tertiary Infotech</strong> - Upon meeting at least 75% attendance and passing the assessment(s), participants will receive a Certificate of Completion from Tertiary Infotech.</p>\r\n</li>\r\n<li>\r\n<p><strong>OpenCerts from SkillsFuture Singapore</strong> - After passing the assessment(s) and achieving at least 75% attendance, participants will receive a OpenCert (aka Statement of Achievement) from SkillsFuture Singapore, certifying that they have&nbsp;achieved the Competency Standard(s) in the above Skills Framework.</p>\r\n</li>\r\n<li><strong>External Certification</strong> -&nbsp;<span>The participant will be able to attempt the CompTIA Cloud+ certification exam after attending this course. Upon passing the exam, you will receive the CompTIA Cloud+ certification. The CompTIA Cloud+ certificationn&nbsp;validates the essential skills to implement, maintain, optimize and troubleshoot cloud-based infrastructure services.</span></li>\r\n</ul>\n<p><strong>Certification Exam at Pearson Vue</strong></p><p>Once you are prepared for the exam, you can register for the certification&nbsp;<span style=\"text-decoration: underline;\"><a href=\"https://home.pearsonvue.com/Clients/CompTIA.aspx\" title=\"CompTia Certification\" target=\"_blank\">here</a></span>. We are Authorised Pearson Vue Testing Center. You can take the certification exam at our test center.</p>', update_time = NOW() WHERE identifier = 'course_TGS-2025053927_certification';
