-- M1048 (entity_id=1048, 2 store row(s))
UPDATE cms_block SET content = '<ul>\r\n<li>\r\n<p><strong>Certificate of Completion from Tertiary Infotech</strong>&nbsp;- Upon meeting at least 75% attendance and passing the assessment(s), participants will receive a Certificate of Completion from Tertiary Infotech.</p>\r\n</li>\r\n<li><strong>External Certification</strong>&nbsp;-&nbsp;The participant will be able to attempt the CompTIA Server+ SK0-005 certification exam after attending this course. Upon passing the exam, you will receive the CompTIA Server+ certification. The CompTIA Server+ certification validates the essential knowledge and skills needed to confidently design, configure, manage, and troubleshoot wired and wireless networks. It covers a wide range of networking concepts including networking technologies, installation and configuration, media and topologies, security, and troubleshooting.</li>\r\n</ul>\n<p><strong>Certification Exam at Pearson Vue</strong></p><p>Once you are prepared for the exam, you can register for the certification&nbsp;<span style=\"text-decoration: underline;\"><a href=\"https://home.pearsonvue.com/Clients/CompTIA.aspx\" title=\"CompTia Certification\" target=\"_blank\">here</a></span>. We are Authorised Pearson Vue Testing Center. You can take the certification exam at our test center. Note that the course fee does not include the certification exam fee.</p>', update_time = NOW() WHERE identifier = 'course_M1048_certification';
